SELECT sales_channel,SUM(amount) AS total_revenue FROM clinic_sales WHERE EXTRACT(YEAR FROM datetime) = 2021 GROUP BY sales_channel;
SELECT uid,SUM(amount) AS total_spent FROM clinic_sales WHERE EXTRACT(YEAR FROM datetime) = 2021 GROUP BY uid ORDER BY total_spent DESC LIMIT 10;
SELECT m.month,COALESCE(s.revenue, 0) AS revenue,COALESCE(e.expense, 0) AS expense,(COALESCE(s.revenue, 0) - COALESCE(e.expense, 0)) AS profit, CASE WHEN (COALESCE(s.revenue, 0) - COALESCE(e.expense, 0)) > 0  THEN 'Profitable' ELSE 'Not Profitable' END AS status FROM ( SELECT generate_series(1,12) AS month) m LEFT JOIN ( SELECT EXTRACT(MONTH FROM datetime) AS month,SUM(amount) AS revenue FROM clinic_sales WHERE EXTRACT(YEAR FROM datetime) = 2021 GROUP BY EXTRACT(MONTH FROM datetime) ) s ON m.month = s.month LEFT JOIN ( SELECT EXTRACT(MONTH FROM datetime) AS month, SUM(amount) AS expense FROM expenses WHERE EXTRACT(YEAR FROM datetime) = 2021 GROUP BY EXTRACT(MONTH FROM datetime) ) e ON m.month = e.month;
SELECT city, cid, profit FROM ( SELECT c.city,cs.cid,SUM(cs.amount) - COALESCE(SUM(e.amount), 0) AS profit,RANK() OVER ( PARTITION BY c.city ORDER BY (SUM(cs.amount) - COALESCE(SUM(e.amount), 0)) DESC ) AS rnk FROM clinics c LEFT JOIN clinic_sales cs ON c.cid = cs.cid LEFT JOIN expenses e ON c.cid = e.cid AND EXTRACT(MONTH FROM e.datetime) = 9 AND EXTRACT(YEAR FROM e.datetime) = 2021 WHERE EXTRACT(MONTH FROM cs.datetime) = 9 AND EXTRACT(YEAR FROM cs.datetime) = 2021 GROUP BY c.city, cs.cid) t WHERE rnk = 1;
SELECT state, cid, profit FROM ( SELECT c.state, cs.cid, SUM(cs.amount) - COALESCE(SUM(e.amount), 0) AS profit, DENSE_RANK() OVER ( PARTITION BY c.state ORDER BY (SUM(cs.amount) - COALESCE(SUM(e.amount), 0) ASC) AS rn FROM clinics c LEFT JOIN clinic_sales cs ON c.cid = cs.cid LEFT JOIN expenses e ON c.cid = e.cid AND EXTRACT(MONTH FROM e.datetime) = 9 AND EXTRACT(YEAR FROM e.datetime) = 2021 WHERE EXTRACT(MONTH FROM cs.datetime) = 9 AND EXTRACT(YEAR FROM cs.datetime) = 2021 GROUP BY c.state, cs.cid) t WHERE rnk = 2;
